/**
 * KS3 Unit — Context (deep route, server-rendered).
 *
 * Source: DfE National Curriculum in England — English programmes of
 *   study: key stage 3 (statutory).
 * https://www.gov.uk/government/publications/national-curriculum-in-england-english-programmes-of-study
 *
 * This route is the per-unit Context deep-dive. The content is
 * generated by `generate_ks3_unit_content.py` and lives in a sibling
 * content.ts file once the corresponding generator wave runs. Until
 * then this scaffolding page renders a placeholder card with the unit
 * metadata so the route exists, is reachable, and can be wired into
 * sitemaps and internal links.
 */
import Link from 'next/link'
import { headers } from 'next/headers'
import { notFound } from 'next/navigation'
import { KS3, type YearNumber, type HalfTermId } from '@/lib/ks3/curriculum'

export default async function KS3UnitDeepPage({
  params,
}: {
  params: Promise<{ year: string; unit: string }>
}) {
  const { year: yearStr, unit } = await params
  const yearNum = Number(yearStr.replace('year-', '')) as YearNumber
  if (![7, 8, 9].includes(yearNum)) notFound()
  const year = KS3.years.find((y) => y.number === yearNum)
  if (!year) notFound()
  const ht = unit.match(/^term-(\d)-half-(\d)$/)
  if (!ht) notFound()
  const halfId = `${ht[1]}.${ht[2]}` as HalfTermId
  const term = year.terms.find((t) => t.halfTerms.some((h) => h.id === halfId))
  const halfTerm = term?.halfTerms.find((h) => h.id === halfId)
  if (!term || !halfTerm) notFound()

  const lang = (await headers()).get('x-lang') === 'ar' ? 'ar' : 'en'
  const enLabel = 'Context'
  const arLabel = 'السياق'

  return (
    <main className="mx-auto max-w-3xl px-6 py-12">
      <p className="font-mono text-[11px] tracking-[0.14em] uppercase text-violet-600 mb-3">
        <Link href={`/ks3/year-${yearNum}/${unit}`}>
          KS3 · Year {yearNum} · {lang === 'ar' ? (term.label.ar ?? term.label.en) : term.label.en}
        </Link>
      </p>
      <h1 className="font-serif text-3xl sm:text-4xl font-bold tracking-tight mb-6">
        {lang === 'ar' ? arLabel : enLabel}
      </h1>
      <div className="rounded-xl border border-amber-400/30 bg-amber-500/[0.04] p-5 mb-8">
        <p className="font-mono text-[10px] uppercase tracking-wider text-amber-700 mb-1">
          {lang === 'ar' ? 'قريباً' : 'Coming soon'}
        </p>
        <p className="text-sm text-foreground leading-relaxed">
          {lang === 'ar'
            ? 'هذا القسم قيد البناء حالياً — المحتوى التفصيلي يولّد بواسطة سلسلة الموجات الذكية المحلية وسيكون متاحاً قريباً.'
            : 'This section is being built right now — detailed content is generated by the local AI wave pipeline and will be available in the next 6–48 hours.'}
        </p>
      </div>
      <p className="text-sm text-muted-foreground">
        <Link href={`/ks3/year-${yearNum}/${unit}`} className="underline">
          ← {lang === 'ar' ? 'الوحدة' : 'Back to unit'}
        </Link>
      </p>
    </main>
  )
}

export async function generateMetadata({
  params,
}: {
  params: Promise<{ year: string; unit: string }>
}) {
  const { year, unit } = await params
  return {
    title: `KS3 ${year.replace('-', ' ')} — Context`,
  }
}
